import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import provided.utils.displayModel.IDimension;

/**
 * @author rlmse
 * A ball that forces perspective, appearing as if it is bouncing out of the screen when moving
 * right and as if it is bouncing away from the screen when moving left.
 */
public class BounceUpBall extends ABall {

	/**
	 * @param color - color of the BounceUpBall
	 * @param position - Position of the BounceUpBall
	 * @param velocity - Velocity of the BounceUpBall
	 * @param diameter - Diameter of the BounceUpBall
	 * @param dimension - Dimension of the graphic container of the BounceUpBall
	 */
	public BounceUpBall(Color color, Point position, Point velocity, int diameter, IDimension dimension) {
		super(color, position, velocity, diameter, dimension);
	}

	@Override
	public void updateState(IDispatcher<Graphics> disp) {
		if (position.x >= 50) {
			diameter = position.x / 5;
		} else {
			diameter = 5;
		}
	}
}

package hw02.ball;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import provided.utils.dispatcher.IObserver;
import provided.utils.displayModel.IDimension;

/**
 * @author rlmse
 * Class which represents abstract balls which can appear in the GUI.
 */
public abstract class ABall implements IObserver<Graphics> {
	/**
	 * Color of the ABall
	 */
	protected Color color;

	/**
	 * Position of the ABall, given as a Point
	 */
	protected Point position;

	/**
	 * Velocity of the ABall, given as a Point representing its x and y components. In pixels per
	 * Refresh cycle.
	 */
	protected Point velocity;

	/**
	 * Diameter of the ball, in pixels
	 */
	protected int diameter;

	/**
	 * Dimension of the graphics object on which the ABall is painted
	 */
	protected IDimension dimension;

	/**
	 * @param color - color of the ABall
	 * @param position - Position of the ABall
	 * @param velocity - Velocity of the ABall
	 * @param diameter - Diameter of the ABall
	 * @param dimension - Dimension of the graphic container of the ABall
	 */
	public ABall(Color color, Point position, Point velocity, int diameter, IDimension dimension) {
		this.color = color;
		this.position = position;
		this.velocity = velocity;
		this.diameter = diameter;
		this.dimension = dimension;
	}

	/**
	 * @param g - the Graphics object containing the ABall
	 */
	public void paint(Graphics g) {
		g.setColor(this.color);
		g.fillOval(this.position.x, this.position.y, diameter, diameter);
	}

	/**
	 * Update the position of the ball to reflect its movement
	 */
	public void move() {
		this.position.translate(this.velocity.x, this.velocity.y);
	}

	/**
	 * Check if the ball has hit a boundary of its container. If so, updates the velocity of the 
	 * ball according to conservation of momentum (perfectly elastic collision).
	 * @return true if the ball bounced of a boundary, false otherwise.
	 */
	public boolean bounce() {
		boolean bounced = false;
		int width = dimension.getWidth();
		int height = dimension.getHeight();
		if (position.x < 0 || position.x + diameter > width) {
			velocity.x = -velocity.x;
			bounced = true;
		}
		if (position.y < 0 || position.y + diameter > height) {
			velocity.y = -velocity.y;
			bounced = true;
		}
		return bounced;
	}

	/**
	 * Update the ball every cycle, according to its defined behavior
	 * @param disp - The dispatcher to which the ball is subscribed 
	 */
	public abstract void updateState(IDispatcher<Graphics> disp);

	public void update(IDispatcher<Graphics> disp, Graphics g) {
		updateState(disp);
		move();
		bounce();
		paint(g);
	}

}

package hw02.ball;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;
import java.awt.Rectangle;

import provided.utils.dispatcher.IDispatcher;
import provided.utils.displayModel.IDimension;
import provided.utils.valueGenerator.impl.Randomizer;
import provided.utils.valueGenerator.impl.SineMaker;

/**
 * @author rlmse
 * A ball whose velocity which oscillates according to randomly generated sine waves
 */
public class SineSpeedBall extends ABall {
	/**
	 * Sine wave used to change the x component of the ball's velocity
	 */
	private final SineMaker xVelChanger;

	/**
	 * Sine wave used to change the y component of the ball's velocity
	 */
	private final SineMaker yVelChanger;

	/**
	 * @param color - color of the SineSpeedBall
	 * @param position - Position of the SineSpeedBall
	 * @param velocity - Velocity of the SineSpeedBall
	 * @param diameter - Diameter of the SineSpeedBall
	 * @param dimension - Dimension of the graphic container of the SineSpeedBall
	 */
	public SineSpeedBall(Color color, Point position, Point velocity, int diameter, IDimension dimension) {
		super(color, position, velocity, diameter, dimension);
		Point velExtreme1 = Randomizer.Singleton.randomVel(new Rectangle(20, 20));
		Point velExtreme2 = Randomizer.Singleton.randomVel(new Rectangle(20, 20));
		xVelChanger = new SineMaker(Math.min(velExtreme1.x, velExtreme2.x), Math.max(velExtreme1.x, velExtreme2.x),
				0.25);
		yVelChanger = new SineMaker(Math.min(velExtreme1.y, velExtreme2.y), Math.max(velExtreme1.y, velExtreme2.y),
				0.25);
	}

	@Override
	public void updateState(IDispatcher<Graphics> disp) {
		velocity.x = xVelChanger.getIntVal();
		velocity.y = yVelChanger.getIntVal();
	}
}

package hw02.ball;

import java.awt.Color;
import java.awt.Graphics;
import java.awt.Point;

import provided.utils.dispatcher.IDispatcher;
import provided.utils.displayModel.IDimension;
import provided.utils.valueGenerator.impl.Randomizer;

/**
 * @author rlmse
 * A ball which changes color when it hits a boundary, like the logo in the DVD idle screen
 */
public class DVDLogoBall extends ABall {

	/**
	 * @param color - color of the DVDLogoBall
	 * @param position - Position of the DVDLogoBall
	 * @param velocity - Velocity of the DVDLogoBall
	 * @param diameter - Diameter of the DVDLogoBall
	 * @param dimension - Dimension of the graphic container of the DVDLogoBall
	 */
	public DVDLogoBall(Color color, Point position, Point velocity, int diameter, IDimension dimension) {
		super(color, position, velocity, diameter, dimension);
	}

	@Override
	/**
	 * Changes the color of the ball if it bounces off a boundary
	 */
	public boolean bounce() {
		boolean bounced = super.bounce();
		if (bounced) {
			this.color = Randomizer.Singleton.randomColor();
		}
		return bounced;
	}

	@Override
	public void updateState(IDispatcher<Graphics> disp) {
		// no-op: color change handled in bounce()
	}
}

